// userAvatarInitials returns the first two letters of a display name as initials.
func userAvatarInitials(displayName, username string) string {
	name := displayName
	if name == "" {
		name = username
	}
	runes := []rune(name)
	switch {
	case len(runes) == 0:
		return "?"
	case len(runes) == 1:
		return string(runes[:1])
	default:
		return string(runes[:2])
	}
}

